:root {
  --whi-bg: #ecefed;
  --whi-panel: rgba(255,255,255,0.97);
  --whi-line: #d6ddd8;
  --whi-text: #22384b;
  --whi-muted: #728191;
  --whi-ok: #178a43;
  --whi-ok-dark: #116833;
  --whi-nok: #d62e2e;
  --whi-idle: #9aa7b5;
  --whi-shadow: 0 22px 45px rgba(24, 38, 52, 0.08);
}
html, body {
  overflow: hidden !important;
}
.nrdb-app {
  --nrdb-font-family: 'Avenir Next', 'Trebuchet MS', sans-serif;
}
body {
  background: linear-gradient(180deg, #f8faf8 0%, var(--whi-bg) 100%);
}
.v-app-bar.v-toolbar {
  display: none !important;
}
.nrdb-ui-page main {
  width: 100%;
  min-height: 100vh;
  padding: 18px;
  display: flex;
  align-items: center;
  justify-content: stretch;
  overflow: hidden;
  box-sizing: border-box;
}
.whi-group > .v-card {
  width: 100%;
  background: transparent;
  border: 0;
  box-shadow: none;
}
.whi-shell {
  width: 100%;
  max-width: none;
}
.whi-panel {
  width: 100%;
  background: var(--whi-panel);
  border: 1px solid var(--whi-line);
  border-radius: 28px;
  box-shadow: var(--whi-shadow);
  padding: 30px;
  box-sizing: border-box;
}
.whi-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 16px;
  margin-bottom: 30px;
  flex-wrap: wrap;
}
.whi-kicker {
  font-size: 11px;
  letter-spacing: 0.16em;
  font-weight: 700;
  text-transform: uppercase;
  color: var(--whi-muted);
}
.whi-title {
  margin-top: 6px;
  font-size: 24px;
  font-weight: 800;
  color: var(--whi-text);
}
.whi-time {
  color: var(--whi-muted);
  background: #edf2f5;
  border: 1px solid var(--whi-line);
  padding: 10px 14px;
  border-radius: 999px;
  font-size: 13px;
  white-space: nowrap;
}
.whi-status-box {
  width: min(100%, 440px);
  margin: 0 auto;
  border-radius: 24px;
  padding: 26px 20px;
  text-align: center;
  color: #fff;
  font-size: 64px;
  font-weight: 900;
  letter-spacing: 0.05em;
  background: linear-gradient(135deg, #9aa7b5 0%, #738090 100%);
}
.whi-status-box.is-ok {
  background: linear-gradient(135deg, #1aa14f 0%, #116833 100%);
}
.whi-status-box.is-nok {
  background: linear-gradient(135deg, #ef4444 0%, #b91c1c 100%);
}
.whi-note {
  margin-top: 18px;
  text-align: center;
  font-size: 19px;
  font-weight: 700;
  color: var(--whi-text);
}
.whi-history {
  margin-top: 32px;
}
.whi-history-head {
  font-size: 16px;
  font-weight: 800;
  color: var(--whi-text);
  margin-bottom: 12px;
}
.whi-history-list {
  display: grid;
  gap: 10px;
}
.whi-history-item {
  display: grid;
  grid-template-columns: 92px 1fr auto;
  gap: 14px;
  align-items: center;
  background: #fbfcfb;
  border: 1px solid var(--whi-line);
  border-radius: 16px;
  padding: 14px 16px;
}
.whi-history-badge {
  text-align: center;
  border-radius: 12px;
  padding: 10px 8px;
  color: #fff;
  font-size: 18px;
  font-weight: 900;
  letter-spacing: 0.04em;
  background: linear-gradient(135deg, #9aa7b5 0%, #738090 100%);
}
.whi-history-badge.is-ok {
  background: linear-gradient(135deg, #1aa14f 0%, #116833 100%);
}
.whi-history-badge.is-nok {
  background: linear-gradient(135deg, #ef4444 0%, #b91c1c 100%);
}
.whi-history-text {
  font-size: 15px;
  font-weight: 700;
  color: var(--whi-text);
}
.whi-history-time {
  font-size: 13px;
  color: var(--whi-muted);
  white-space: nowrap;
}
.whi-empty {
  background: #fbfcfb;
  border: 1px dashed var(--whi-line);
  border-radius: 16px;
  padding: 16px;
  text-align: center;
  color: var(--whi-muted);
}
@media (max-width: 900px) {
  .whi-history-item {
    grid-template-columns: 1fr;
    text-align: center;
  }
  .whi-history-time {
    white-space: normal;
  }
}
@media (max-width: 640px) {
  html, body {
    overflow: auto !important;
  }
  .nrdb-ui-page main {
    min-height: auto;
    align-items: stretch;
    overflow: auto;
    padding: 12px;
  }
  .whi-panel {
    padding: 18px;
    border-radius: 22px;
  }
  .whi-title {
    font-size: 20px;
  }
  .whi-status-box {
    width: 100%;
    font-size: 42px;
  }
}

