const payload = msg.payload || {};
const state = flow.get('whi_dashboard') || { history: [] };
state.status = payload.status || 'EN ATTENTE';
state.mode = payload.mode || '-';
state.confidence = payload.confidence;
state.timestamp = payload.timestamp || new Date().toISOString();
let note = 'Toutes les regles sont satisfaites';
if ((payload.missing_classes || []).length) {
    note = `Manquant : ${payload.missing_classes.map(frLabel).join(', ')}`;
} else if ((payload.misplaced_classes || []).length) {
    note = `Mal positionne : ${payload.misplaced_classes.map(frLabel).join(', ')}`;
} else if ((payload.failed_zone_ids || []).length) {
    note = `Zone en echec : ${payload.failed_zone_ids.join(', ')}`;
} else if ((payload.details || []).length) {
    note = frLabel(payload.details[0]);
} else if (payload.anomaly_label) {
    note = frLabel(payload.anomaly_label);
}
state.note = note;
flow.set('whi_dashboard', state);
msg.payload = {
    status: state.status,
    mode: state.mode,
    confidence: state.confidence,
    timestamp: state.timestamp,
    note: state.note,
    history: state.history || []
};
return msg;

function frLabel(text) {
    return String(text || '')
        .replace(/status=OK/gi, 'Statut OK')
        .replace(/status=NOK/gi, 'Statut NOK')
        .replace(/missing:/gi, 'Manquant : ')
        .replace(/missing /gi, 'manquant ')
        .replace(/misplaced:/gi, 'Mal positionne : ')
        .replace(/misplaced /gi, 'mal positionne ')
        .replace(/failed zone:/gi, 'Zone en echec : ')
        .replace(/connector/gi, 'connecteur')
        .replace(/cable/gi, 'cable')
        .replace(/clip/gi, 'clip');
}
const payload = msg.payload || {};
const state = flow.get('whi_dashboard') || { history: [] };
let history = Array.isArray(state.history) ? state.history : [];
const entry = {
    status: payload.status || state.status || 'INFO',
    message: frLabel(payload.message || payload.anomaly_label || 'Evenement d inspection'),
    timestamp: payload.timestamp || new Date().toISOString()
};
const first = history[0];
if (first && first.status === entry.status && first.message === entry.message) {
    history[0] = entry;
} else {
    history.unshift(entry);
}
history = history.slice(0, 4);
state.history = history;
flow.set('whi_dashboard', state);
msg.payload = {
    status: state.status || 'EN ATTENTE',
    mode: state.mode || '-',
    confidence: state.confidence,
    timestamp: state.timestamp || entry.timestamp,
    note: state.note || 'En attente de donnees',
    history: state.history
};
return msg;
